import { Component, Prop, h, Element, Event, EventEmitter, Host } from '@stencil/core';

@Component({
  tag: 'wdpr-segmented-vertical-tab',
  styleUrl: 'wdpr-segmented-vertical-tab.css',
  scoped: true,
})
export class WdprSegmentedVerticalTab {
  @Element() el: HTMLWdprSegmentedVerticalTabElement;

  /**
   * Tab id
   * @type {string}
   */
  @Prop() tabId: string;

  /**
   * Tab label
   * @type {string}
   */
  @Prop() label: string;

  /**
   * Tab secondary label
   * @type {string}
   */
  @Prop() secondaryLabel: string;

  /**
   * Tab icon
   * @type {string}
   */
  @Prop() icon: string;

  /**
   * if `true`, the tab is currently active.
   * @type {boolean}
   */
  @Prop({ reflect: true, mutable: true }) active: boolean = false;

  /**
   * if `true`, the tab is disabled
   * @type {boolean}
   */
  @Prop({ reflect: true, mutable: true }) disabled: boolean = false;

  /**
   * The id of the element that this tab controls
   * @type {string}
   */
  @Prop() controlsId: string;

  /**
   * The tabindex of the tab
   * @type {number}
   */
  @Prop() customTabIndex: number;

  /**
   * Emitted when the tab button is clicked.
   * This is used by the parent wdpr-tab-bar to manage the active state.
   */
  @Event() tabClicked: EventEmitter<{ tabElement: unknown }>;

  private _handleClick = (): void => {
    if (this.disabled) return;

    this.tabClicked.emit({ tabElement: this.el });
  };

  render() {
    return (
      <Host
        id={this.tabId}
        role="tab"
        aria-selected={this.active ? 'true' : 'false'}
        aria-controls={this.controlsId}
        aria-disabled={this.disabled ? 'true' : undefined}
        tabindex={this.disabled ? -1 : (this.customTabIndex ?? 0)}
        onClick={this._handleClick}
        disabled={this.disabled}
      >
        <div class="segmented-vertical-tab-icon-wrapper">
          {this.icon && <wdpr-icon-library icon={this.icon} size="medium" decorative={true}></wdpr-icon-library>}
          {this.secondaryLabel && !this.icon && <span class="segmented-vertical-tab-secondary-label">{this.secondaryLabel}</span>}
        </div>
        <span class="segmented-vertical-tab-main-label">{this.label}</span>
      </Host>
    );
  }
}
